package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testIsLineBreakWithNullCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, new Object[]{(Character) null});
        assertFalse(result);
    }

    @Test
    void testIsLineBreakWithLineFeedCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Character lf = '\n';
        Boolean result = (Boolean) method.invoke(null, lf);
        assertTrue(result);
    }

    @Test
    void testIsLineBreakWithCarriageReturnCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Character cr = '\r';
        Boolean result = (Boolean) method.invoke(null, cr);
        assertTrue(result);
    }

    @Test
    void testIsLineBreakWithNonLineBreakCharacter() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Character c = 'a';
        Boolean result = (Boolean) method.invoke(null, c);
        assertFalse(result);
    }

    @Test
    void testIsLineBreakCharLF() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) '\n');
        assertTrue(result);
    }

    @Test
    void testIsLineBreakCharCR() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) '\r');
        assertTrue(result);
    }

    @Test
    void testIsLineBreakCharOther() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) 'x');
        assertFalse(result);
    }
}
